SELECT component_id, MAX(update_date) AS latest_update
FROM component_history
GROUP BY component_id;

SELECT AVG(num_parameters) as avg_parameters
FROM (
    SELECT component_id, COUNT(parameter_id) AS num_parameters
    FROM component_parameters
    GROUP BY component_id
);

SELECT component_id
FROM component_units
WHERE parameter_id = 1 AND unit_id = 0;

SELECT * FROM components 
WHERE vendor_id = (
    SELECT vendor_id 
    FROM vendors 
    WHERE vendor_name = 'Your Vendor Name'
);

SELECT tc.test_condition_id, tc.test_condition_name, ctc.test_result, ctc.test_duration
FROM test_conditions tc
JOIN component_test_conditions ctc ON tc.test_condition_id = ctc.test_condition_id;
